import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty array for empty grid");
  it.todo("should kill a single live cell with no neighbors");
  it.todo("should kill cells with only one neighbor (underpopulation)");
  it.todo("should keep alive a live cell with 2 live neighbors (survival)");
  it.todo("should keep alive a live cell with 3 live neighbors (survival)");
  it.todo("should kill a live cell with 4 live neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
  it.todo("should keep a block pattern unchanged (still life)");
  it.todo("should oscillate a vertical blinker into a horizontal blinker");
});
